'use client';

import React, { createContext, useContext, useState, useEffect } from 'react';
import { defaultPortfolioData, PortfolioData } from '../data/defaultData';

export interface OSWindow {
  id: string;
  title: string;
  icon: string; // Lucide icon name
  isOpen: boolean;
  isMaximized: boolean;
  isMinimized: boolean;
  x: number;
  y: number;
  w: number;
  h: number;
  zIndex: number;
  launchMode?: 'desktop' | 'iframe' | 'new_tab' | 'popup';
}

export interface Note {
  id: string;
  title: string;
  content: string;
  date: string;
  pinned: boolean;
}

export interface Task {
  id: string;
  text: string;
  completed: boolean;
  date: string;
}

export interface Goal {
  id: string;
  title: string;
  status: 'pending' | 'in-progress' | 'completed';
  deadline: string;
}

export interface Bookmark {
  id: string;
  name: string;
  url: string;
  category: string;
}

export interface ContactMessage {
  id: string;
  name: string;
  email: string;
  message: string;
  date: string;
  unread: boolean;
}

export type OSTheme = 
  | 'glass' 
  | 'apple' 
  | 'batman' 
  | 'cyberpunk' 
  | 'neon' 
  | 'matrix' 
  | 'dark' 
  | 'light' 
  | 'gaming' 
  | 'minimal' 
  | 'luxury' 
  | 'space' 
  | 'ocean';

export type OSWallpaper = 
  | 'space' 
  | 'rain' 
  | 'cave' 
  | 'cyber-city' 
  | 'gradient' 
  | 'particles' 
  | 'aurora' 
  | 'abstract' 
  | 'water'
  | 'live-video';

export type OSFont = 
  | 'Inter' 
  | 'Poppins' 
  | 'Montserrat' 
  | 'Outfit' 
  | 'Space Grotesk' 
  | 'Sora' 
  | 'Orbitron' 
  | 'Audiowide' 
  | 'Manrope';

export type OSColor = 
  | 'blue' 
  | 'cyan' 
  | 'purple' 
  | 'emerald' 
  | 'red' 
  | 'orange' 
  | 'gold' 
  | 'pink' 
  | 'gradient' 
  | 'custom';

interface OSContextType {
  // OS System States
  theme: OSTheme;
  setTheme: (t: OSTheme) => void;
  wallpaper: OSWallpaper;
  setWallpaper: (w: OSWallpaper) => void;
  font: OSFont;
  setFont: (f: OSFont) => void;
  colorTheme: OSColor;
  setColorTheme: (c: OSColor) => void;
  customAccent: string;
  setCustomAccent: (hex: string) => void;
  
  // Audio Player States
  musicPlaying: boolean;
  setMusicPlaying: (p: boolean) => void;
  musicVolume: number;
  setMusicVolume: (v: number) => void;
  
  // Window Manager States
  windows: OSWindow[];
  setWindows: React.Dispatch<React.SetStateAction<OSWindow[]>>;
  activeWindowId: string | null;
  openWindow: (id: string, mode?: 'desktop' | 'iframe' | 'new_tab' | 'popup') => void;
  closeWindow: (id: string) => void;
  minimizeWindow: (id: string) => void;
  maximizeWindow: (id: string) => void;
  focusWindow: (id: string) => void;
  resetWindowPositions: () => void;
  
  // CMS Editable Data
  portfolioData: PortfolioData;
  updatePortfolioData: (data: Partial<PortfolioData>) => void;
  
  // Productivity Tools States
  notes: Note[];
  addNote: (title: string, content: string) => void;
  updateNote: (id: string, title: string, content: string) => void;
  deleteNote: (id: string) => void;
  togglePinNote: (id: string) => void;
  
  tasks: Task[];
  addTask: (text: string) => void;
  toggleTask: (id: string) => void;
  deleteTask: (id: string) => void;
  
  goals: Goal[];
  addGoal: (title: string, deadline: string) => void;
  updateGoalStatus: (id: string, status: Goal['status']) => void;
  deleteGoal: (id: string) => void;
  
  bookmarks: Bookmark[];
  addBookmark: (name: string, url: string, category: string) => void;
  deleteBookmark: (id: string) => void;
  
  // Contact Panel Messages
  messages: ContactMessage[];
  addMessage: (name: string, email: string, message: string) => void;
  markMessageRead: (id: string) => void;
  deleteMessage: (id: string) => void;
  
  // Global Search State
  searchQuery: string;
  setSearchQuery: (q: string) => void;
}

const OSContext = createContext<OSContextType | undefined>(undefined);

const initialWindowsList: OSWindow[] = [
  { id: 'portfolio', title: 'My Portfolio', icon: 'User', isOpen: false, isMaximized: false, isMinimized: false, x: 80, y: 60, w: 900, h: 620, zIndex: 10 },
  { id: 'ai_dashboard', title: 'AI Command Center', icon: 'Cpu', isOpen: false, isMaximized: false, isMinimized: false, x: 120, y: 100, w: 950, h: 640, zIndex: 1 },
  { id: 'marketing_desk', title: 'Marketing Desk', icon: 'BarChart3', isOpen: false, isMaximized: false, isMinimized: false, x: 160, y: 80, w: 920, h: 600, zIndex: 1 },
  { id: 'workspace', title: 'Workspace Tools', icon: 'FolderOpen', isOpen: false, isMaximized: false, isMinimized: false, x: 200, y: 120, w: 880, h: 580, zIndex: 1 },
  { id: 'admin', title: 'OS Admin Panel', icon: 'Settings', isOpen: false, isMaximized: false, isMinimized: false, x: 240, y: 140, w: 850, h: 560, zIndex: 1 }
];

export const OSProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  // Theme and customization states
  const [theme, setTheme] = useState<OSTheme>('glass');
  const [wallpaper, setWallpaper] = useState<OSWallpaper>('space');
  const [font, setFont] = useState<OSFont>('Outfit');
  const [colorTheme, setColorTheme] = useState<OSColor>('cyan');
  const [customAccent, setCustomAccent] = useState<string>('#06b6d4');
  
  // Audio state
  const [musicPlaying, setMusicPlaying] = useState<boolean>(false);
  const [musicVolume, setMusicVolume] = useState<number>(0.3);
  
  // Windows manager state
  const [windows, setWindows] = useState<OSWindow[]>(initialWindowsList);
  const [activeWindowId, setActiveWindowId] = useState<string | null>(null);
  const [maxZIndex, setMaxZIndex] = useState<number>(10);
  
  // CMS Editable Portfolio Data
  const [portfolioData, setPortfolioData] = useState<PortfolioData>(defaultPortfolioData);
  
  // Workspace productivity states
  const [notes, setNotes] = useState<Note[]>([]);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [goals, setGoals] = useState<Goal[]>([]);
  const [bookmarks, setBookmarks] = useState<Bookmark[]>([]);
  const [messages, setMessages] = useState<ContactMessage[]>([]);
  
  const [searchQuery, setSearchQuery] = useState<string>('');

  // Load state from localStorage on mount
  useEffect(() => {
    if (typeof window === 'undefined') return;
    
    const timer = setTimeout(() => {
      const savedTheme = localStorage.getItem('os_theme') as OSTheme;
      if (savedTheme) setTheme(savedTheme);

      const savedWallpaper = localStorage.getItem('os_wallpaper') as OSWallpaper;
      if (savedWallpaper) setWallpaper(savedWallpaper);

      const savedFont = localStorage.getItem('os_font') as OSFont;
      if (savedFont) setFont(savedFont);

      const savedColorTheme = localStorage.getItem('os_color_theme') as OSColor;
      if (savedColorTheme) setColorTheme(savedColorTheme);

      const savedCustomAccent = localStorage.getItem('os_custom_accent');
      if (savedCustomAccent) setCustomAccent(savedCustomAccent);

      const savedPortfolio = localStorage.getItem('os_portfolio_data');
      if (savedPortfolio) {
        try {
          setPortfolioData(JSON.parse(savedPortfolio));
        } catch (e) {
          console.error("Failed to parse saved portfolio data", e);
        }
      }

      const savedNotes = localStorage.getItem('os_notes');
      if (savedNotes) {
        try { setNotes(JSON.parse(savedNotes)); } catch { }
      } else {
        const defaultNotes: Note[] = [
          { id: 'n-1', title: 'Ad Strategy Notes', content: 'For Meta Ads Advantage+ campaigns:\n1. Consolidate ad sets to give algorithm enough conversion data.\n2. Keep 3-5 distinct creative formats running (video hook, static carousel, testimonials).\n3. Budget at least 50 conversions per week per ad set.', date: new Date().toLocaleDateString(), pinned: true },
          { id: 'n-2', title: 'SEO Checklist', content: '- Audit duplicate H1s\n- Configure schema markup (Article, Organization, FAQ)\n- Implement absolute paths for canonical tags\n- Shrink and compress layout banners to WebP format', date: new Date().toLocaleDateString(), pinned: false }
        ];
        setNotes(defaultNotes);
        localStorage.setItem('os_notes', JSON.stringify(defaultNotes));
      }

      const savedTasks = localStorage.getItem('os_tasks');
      if (savedTasks) {
        try { setTasks(JSON.parse(savedTasks)); } catch { }
      } else {
        const defaultTasks: Task[] = [
          { id: 't-1', text: 'Set up GA4 custom conversion event tracking for Manoj portfolio', completed: false, date: new Date().toLocaleDateString() },
          { id: 't-2', text: 'Audit client Google Ads Search budget keyword match types', completed: true, date: new Date().toLocaleDateString() },
          { id: 't-3', text: 'Draft LinkedIn strategy blog post using AI Dashboard tools', completed: false, date: new Date().toLocaleDateString() }
        ];
        setTasks(defaultTasks);
        localStorage.setItem('os_tasks', JSON.stringify(defaultTasks));
      }

      const savedGoals = localStorage.getItem('os_goals');
      if (savedGoals) {
        try { setGoals(JSON.parse(savedGoals)); } catch { }
      } else {
        const defaultGoals: Goal[] = [
          { id: 'g-1', title: 'Increase website load speed score to 95+', status: 'in-progress', deadline: '2026-08-01' },
          { id: 'g-2', title: 'Obtain Google Ads Measurement Certification', status: 'completed', deadline: '2026-07-15' },
          { id: 'g-3', title: 'Launch n8n automation for lead capturing', status: 'pending', deadline: '2026-08-15' }
        ];
        setGoals(defaultGoals);
        localStorage.setItem('os_goals', JSON.stringify(defaultGoals));
      }

      const savedBookmarks = localStorage.getItem('os_bookmarks');
      if (savedBookmarks) {
        try { setBookmarks(JSON.parse(savedBookmarks)); } catch { }
      } else {
        const defaultBookmarks: Bookmark[] = [
          { id: 'b-1', name: 'Google Ads Manager', url: 'https://ads.google.com', category: 'Advertising' },
          { id: 'b-2', name: 'Meta Business Suite', url: 'https://business.facebook.com', category: 'Advertising' },
          { id: 'b-3', name: 'Google Analytics 4', url: 'https://analytics.google.com', category: 'Analytics' },
          { id: 'b-4', name: 'Google Search Console', url: 'https://search.google.com/search-console', category: 'Analytics' },
          { id: 'b-5', name: 'Ahrefs Site Explorer', url: 'https://ahrefs.com', category: 'SEO Tools' },
          { id: 'b-6', name: 'Canva Pro Workspace', url: 'https://canva.com', category: 'Creative' }
        ];
        setBookmarks(defaultBookmarks);
        localStorage.setItem('os_bookmarks', JSON.stringify(defaultBookmarks));
      }

      const savedMessages = localStorage.getItem('os_messages');
      if (savedMessages) {
        try { setMessages(JSON.parse(savedMessages)); } catch { }
      } else {
        const defaultMessages: ContactMessage[] = [
          { id: 'm-1', name: 'Sarah Connor', email: 'sarah@skynet.com', message: 'Hello Manoj, we saw your ROAS case study and would love to schedule a 30-minute discovery call to scale our ecommerce brand.', date: new Date().toLocaleString(), unread: true },
          { id: 'm-2', name: 'Bruce Wayne', email: 'bruce@waynecorp.com', message: 'Manoj, Wayne Enterprises needs a stealth SEO strategy for our upcoming R&D division launch. Budget is not an issue.', date: new Date().toLocaleString(), unread: false }
        ];
        setMessages(defaultMessages);
        localStorage.setItem('os_messages', JSON.stringify(defaultMessages));
      }

      // Load saved launch modes
      setWindows(prev => prev.map(win => {
        const savedMode = localStorage.getItem(`launch_mode_${win.id}`);
        if (savedMode) {
          return { ...win, launchMode: savedMode as any };
        }
        return win;
      }));
    }, 0);

    return () => clearTimeout(timer);
  }, []);

  // Message listener for standalone popup closures
  useEffect(() => {
    if (typeof window === 'undefined') return;
    const handleMessage = (e: MessageEvent) => {
      if (e.data && e.data.type === 'APP_CLOSED') {
        const appId = e.data.appId;
        setWindows(prev => prev.map(win => {
          if (win.id === appId) {
            return { ...win, isOpen: false };
          }
          return win;
        }));
      }
    };
    window.addEventListener('message', handleMessage);
    return () => window.removeEventListener('message', handleMessage);
  }, []);

  // Save states to localStorage when they change
  useEffect(() => {
    localStorage.setItem('os_theme', theme);
    // Apply styling root attributes
    document.documentElement.setAttribute('data-theme', theme);
  }, [theme]);

  useEffect(() => {
    localStorage.setItem('os_wallpaper', wallpaper);
  }, [wallpaper]);

  useEffect(() => {
    localStorage.setItem('os_font', font);
    // Dynamic fonts loader
    const fontId = 'dynamic-font-stylesheet';
    let link = document.getElementById(fontId) as HTMLLinkElement;
    if (!link) {
      link = document.createElement('link');
      link.id = fontId;
      link.rel = 'stylesheet';
      document.head.appendChild(link);
    }
    const fontUrlName = font.replace(/\s+/g, '+');
    link.href = `https://fonts.googleapis.com/css2?family=${fontUrlName}:wght@300;400;500;600;700;800&display=swap`;
    
    // Set custom font CSS variable
    document.documentElement.style.setProperty('--theme-font', `'${font}', sans-serif`);
  }, [font]);

  useEffect(() => {
    localStorage.setItem('os_color_theme', colorTheme);
    let accent = '#06b6d4'; // default cyan
    switch (colorTheme) {
      case 'blue': accent = '#2563eb'; break;
      case 'cyan': accent = '#06b6d4'; break;
      case 'purple': accent = '#8b5cf6'; break;
      case 'emerald': accent = '#10b981'; break;
      case 'red': accent = '#ef4444'; break;
      case 'orange': accent = '#f97316'; break;
      case 'gold': accent = '#d97706'; break;
      case 'pink': accent = '#ec4899'; break;
      case 'custom': accent = customAccent; break;
      case 'gradient': accent = 'linear-gradient(135deg, #a855f7 0%, #06b6d4 100%)'; break;
    }
    document.documentElement.style.setProperty('--theme-accent', accent);
  }, [colorTheme, customAccent]);

  // Window Manager Actions
  const openWindow = (id: string, mode?: 'desktop' | 'iframe' | 'new_tab' | 'popup') => {
    // Determine target mode (from arguments or stored settings)
    const targetMode = mode || windows.find(w => w.id === id)?.launchMode || 'desktop';
    
    if (targetMode === 'new_tab') {
      window.open(`/?app=${id}`, '_blank');
      return;
    }
    
    if (targetMode === 'popup') {
      const w = 1000;
      const h = 700;
      const left = (window.innerWidth - w) / 2 + window.screenX;
      const top = (window.innerHeight - h) / 2 + window.screenY;
      window.open(`/?app=${id}`, `popup-${id}`, `width=${w},height=${h},top=${top},left=${left},menubar=no,toolbar=no,location=no,status=no`);
      return;
    }
    
    const nextZ = maxZIndex + 1;
    setMaxZIndex(nextZ);
    setWindows(prev => prev.map(win => {
      if (win.id === id) {
        return { 
          ...win, 
          isOpen: true, 
          isMinimized: false, 
          zIndex: nextZ,
          launchMode: mode || win.launchMode || 'desktop'
        };
      }
      return win;
    }));
    setActiveWindowId(id);
  };

  const closeWindow = (id: string) => {
    setWindows(prev => prev.map(win => {
      if (win.id === id) {
        return { ...win, isOpen: false };
      }
      return win;
    }));
    if (activeWindowId === id) {
      // Find another open and non-minimized window to focus
      const openWins = windows.filter(w => w.id !== id && w.isOpen && !w.isMinimized);
      if (openWins.length > 0) {
        const sorted = [...openWins].sort((a, b) => b.zIndex - a.zIndex);
        setActiveWindowId(sorted[0].id);
      } else {
        setActiveWindowId(null);
      }
    }
  };

  const minimizeWindow = (id: string) => {
    setWindows(prev => prev.map(win => {
      if (win.id === id) {
        return { ...win, isMinimized: true };
      }
      return win;
    }));
    if (activeWindowId === id) {
      const openWins = windows.filter(w => w.id !== id && w.isOpen && !w.isMinimized);
      if (openWins.length > 0) {
        const sorted = [...openWins].sort((a, b) => b.zIndex - a.zIndex);
        setActiveWindowId(sorted[0].id);
      } else {
        setActiveWindowId(null);
      }
    }
  };

  const maximizeWindow = (id: string) => {
    setWindows(prev => prev.map(win => {
      if (win.id === id) {
        return { ...win, isMaximized: !win.isMaximized };
      }
      return win;
    }));
    focusWindow(id);
  };

  const focusWindow = (id: string) => {
    const nextZ = maxZIndex + 1;
    setMaxZIndex(nextZ);
    setWindows(prev => prev.map(win => {
      if (win.id === id) {
        return { ...win, isMinimized: false, zIndex: nextZ };
      }
      return win;
    }));
    setActiveWindowId(id);
  };

  const resetWindowPositions = () => {
    setWindows(initialWindowsList);
    setActiveWindowId('portfolio');
    setMaxZIndex(10);
  };

  // CMS functions
  const updatePortfolioData = (updatedFields: Partial<PortfolioData>) => {
    setPortfolioData(prev => {
      const newData = { ...prev, ...updatedFields };
      localStorage.setItem('os_portfolio_data', JSON.stringify(newData));
      return newData;
    });
  };

  // Notes actions
  const addNote = (title: string, content: string) => {
    const newNote: Note = {
      id: `n-${Date.now()}`,
      title: title || 'Untitled Note',
      content: content || '',
      date: new Date().toLocaleDateString(),
      pinned: false
    };
    const updated = [newNote, ...notes];
    setNotes(updated);
    localStorage.setItem('os_notes', JSON.stringify(updated));
  };

  const updateNote = (id: string, title: string, content: string) => {
    const updated = notes.map(note => {
      if (note.id === id) {
        return { ...note, title, content };
      }
      return note;
    });
    setNotes(updated);
    localStorage.setItem('os_notes', JSON.stringify(updated));
  };

  const deleteNote = (id: string) => {
    const updated = notes.filter(n => n.id !== id);
    setNotes(updated);
    localStorage.setItem('os_notes', JSON.stringify(updated));
  };

  const togglePinNote = (id: string) => {
    const updated = notes.map(note => {
      if (note.id === id) {
        return { ...note, pinned: !note.pinned };
      }
      return note;
    });
    setNotes(updated);
    localStorage.setItem('os_notes', JSON.stringify(updated));
  };

  // Tasks actions
  const addTask = (text: string) => {
    const newTask: Task = {
      id: `t-${Date.now()}`,
      text,
      completed: false,
      date: new Date().toLocaleDateString()
    };
    const updated = [newTask, ...tasks];
    setTasks(updated);
    localStorage.setItem('os_tasks', JSON.stringify(updated));
  };

  const toggleTask = (id: string) => {
    const updated = tasks.map(task => {
      if (task.id === id) {
        return { ...task, completed: !task.completed };
      }
      return task;
    });
    setTasks(updated);
    localStorage.setItem('os_tasks', JSON.stringify(updated));
  };

  const deleteTask = (id: string) => {
    const updated = tasks.filter(t => t.id !== id);
    setTasks(updated);
    localStorage.setItem('os_tasks', JSON.stringify(updated));
  };

  // Goals actions
  const addGoal = (title: string, deadline: string) => {
    const newGoal: Goal = {
      id: `g-${Date.now()}`,
      title,
      status: 'pending',
      deadline: deadline || new Date().toISOString().split('T')[0]
    };
    const updated = [newGoal, ...goals];
    setGoals(updated);
    localStorage.setItem('os_goals', JSON.stringify(updated));
  };

  const updateGoalStatus = (id: string, status: Goal['status']) => {
    const updated = goals.map(g => {
      if (g.id === id) {
        return { ...g, status };
      }
      return g;
    });
    setGoals(updated);
    localStorage.setItem('os_goals', JSON.stringify(updated));
  };

  const deleteGoal = (id: string) => {
    const updated = goals.filter(g => g.id !== id);
    setGoals(updated);
    localStorage.setItem('os_goals', JSON.stringify(updated));
  };

  // Bookmarks actions
  const addBookmark = (name: string, url: string, category: string) => {
    let absoluteUrl = url;
    if (!url.startsWith('http://') && !url.startsWith('https://')) {
      absoluteUrl = `https://${url}`;
    }
    const newBookmark: Bookmark = {
      id: `b-${Date.now()}`,
      name,
      url: absoluteUrl,
      category: category || 'General'
    };
    const updated = [...bookmarks, newBookmark];
    setBookmarks(updated);
    localStorage.setItem('os_bookmarks', JSON.stringify(updated));
  };

  const deleteBookmark = (id: string) => {
    const updated = bookmarks.filter(b => b.id !== id);
    setBookmarks(updated);
    localStorage.setItem('os_bookmarks', JSON.stringify(updated));
  };

  // Message actions
  const addMessage = (name: string, email: string, message: string) => {
    const newMessage: ContactMessage = {
      id: `m-${Date.now()}`,
      name,
      email,
      message,
      date: new Date().toLocaleString(),
      unread: true
    };
    const updated = [newMessage, ...messages];
    setMessages(updated);
    localStorage.setItem('os_messages', JSON.stringify(updated));
  };

  const markMessageRead = (id: string) => {
    const updated = messages.map(m => {
      if (m.id === id) {
        return { ...m, unread: false };
      }
      return m;
    });
    setMessages(updated);
    localStorage.setItem('os_messages', JSON.stringify(updated));
  };

  const deleteMessage = (id: string) => {
    const updated = messages.filter(m => m.id !== id);
    setMessages(updated);
    localStorage.setItem('os_messages', JSON.stringify(updated));
  };

  return (
    <OSContext.Provider value={{
      theme, setTheme,
      wallpaper, setWallpaper,
      font, setFont,
      colorTheme, setColorTheme,
      customAccent, setCustomAccent,
      musicPlaying, setMusicPlaying,
      musicVolume, setMusicVolume,
      windows, setWindows, activeWindowId,
      openWindow, closeWindow, minimizeWindow, maximizeWindow, focusWindow, resetWindowPositions,
      portfolioData, updatePortfolioData,
      notes, addNote, updateNote, deleteNote, togglePinNote,
      tasks, addTask, toggleTask, deleteTask,
      goals, addGoal, updateGoalStatus, deleteGoal,
      bookmarks, addBookmark, deleteBookmark,
      messages, addMessage, markMessageRead, deleteMessage,
      searchQuery, setSearchQuery
    }}>
      {children}
    </OSContext.Provider>
  );
};

export const useOS = () => {
  const context = useContext(OSContext);
  if (!context) {
    throw new Error('useOS must be used within an OSProvider');
  }
  return context;
};
